begin;
create extension if not exists pgtap with schema extensions;
select plan(27);

insert into auth.users(id,email) values ('00000000-0000-0000-0000-000000005001','restore-news@example.test');
create function public.test_restore_news_job(p_hash text,p_count integer) returns uuid language sql set search_path='' as $$
 select (public.create_restore_job('daily-brief-note-backup',1,'core',p_hash,'daily-brief-note-restore-plan',1,1,repeat(substr(p_hash,1,1),64),repeat('f',64),'ready','news.json','{"operationalHistory":"exclude","timestamps":"preserve"}','[{"sourceCategoryId":"economy","targetCategoryId":"economy","status":"compatible","target":{"contentGroup":"news","code":"ECO"}}]','[]',p_count)->>'jobId')::uuid;
$$;
create function public.test_restore_news_record(p_section text,p_source text,p_target text,p_stage integer,p_sequence integer,p_payload jsonb,p_dependencies jsonb default '[]',p_action text default 'preserve_id') returns jsonb language sql security definer set search_path='' as $$
 select jsonb_build_object('section',p_section,'sourceId',p_source,'targetId',p_target,'action',p_action,'stageKey','stage-'||p_stage,'stageOrder',p_stage,'sequenceNo',p_sequence,'payload',p_payload,'payloadFingerprint',public.restore_payload_fingerprint(p_payload),'dependencies',p_dependencies,'safeDisplay',p_source);
$$;
create function public.test_restore_news_post(p_slug text,p_title text,p_briefing date default '2026-07-20') returns jsonb language sql immutable as $$ select jsonb_build_object('categoryId','economy','seriesNo',null,'briefingDate',p_briefing,'publishedOn',p_briefing,'displayId','#'||p_briefing::text||'-ECO','title',p_title,'summary','summary','htmlBody','<article>news</article>','slug',p_slug,'wordpressUrl',null,'contentStatus','draft','publishedAt',null,'sourceImportType','json_import','imagePrompt',null,'imageAlt',null,'imagePromptVersion',1,'imagePromptUpdatedAt',null,'createdAt','2026-07-15T00:00:00Z','updatedAt','2026-07-15T00:00:00Z') $$;
create function public.test_run_restore_news_job(p_job uuid) returns integer language plpgsql set search_path='' as $$ declare r record; n integer:=0; begin for r in select id from public.restore_job_records where job_id=p_job order by stage_order,sequence_no loop perform public.run_restore_job_record(r.id); n:=n+1; end loop; return n; end $$;

set local role authenticated;
set local "request.jwt.claims"='{"sub":"00000000-0000-0000-0000-000000005001","role":"authenticated"}';
create temporary table news_jobs(name text primary key,id uuid);
insert into news_jobs values('main',public.test_restore_news_job(repeat('a',64),10));
select public.append_restore_job_records((select id from news_jobs where name='main'),jsonb_build_array(
 public.test_restore_news_record('posts','post-one','50100000-0000-0000-0000-000000000001',1,0,public.test_restore_news_post('news-post-one','뉴스 글 1'),'["category:economy"]'),
 public.test_restore_news_record('posts','post-two','50100000-0000-0000-0000-000000000002',1,1,public.test_restore_news_post('news-post-two','뉴스 글 2','2026-07-21'),'["category:economy"]'),
 public.test_restore_news_record('newsTopics','topic-one','50200000-0000-0000-0000-000000000001',2,0,'{"categoryId":"economy","topicKey":"economy-topic","canonicalTitle":"경제 주제","topicSummary":"요약","status":"active","closedReason":null,"firstSeenAt":"2026-07-01","lastSeenAt":"2026-07-15","createdAt":"2026-07-01T00:00:00Z","updatedAt":"2026-07-15T00:00:00Z"}','["category:economy"]'),
 public.test_restore_news_record('newsStatusHistory','history-one','50300000-0000-0000-0000-000000000001',3,0,'{"topicId":"topic-one","fromStatus":null,"toStatus":"active","reason":"생성","changedAt":"2026-07-01T01:00:00Z"}','["newsTopics:topic-one"]'),
 public.test_restore_news_record('newsUpdates','update-one','50400000-0000-0000-0000-000000000001',4,0,'{"postId":"post-one","topicId":"topic-one","itemOrder":1,"updateType":"new","headline":"첫 업데이트","factSummary":"사실 1","importanceSummary":null,"impactSummary":null,"changeSummary":null,"previousUpdateId":null,"createdAt":"2026-07-10T00:00:00Z","updatedAt":"2026-07-10T00:00:00Z"}','["posts:post-one","newsTopics:topic-one"]'),
 public.test_restore_news_record('newsUpdates','update-two','50400000-0000-0000-0000-000000000002',4,1,'{"postId":"post-two","topicId":"topic-one","itemOrder":2,"updateType":"follow_up","headline":"후속 업데이트","factSummary":"사실 2","importanceSummary":"중요","impactSummary":null,"changeSummary":"변화","previousUpdateId":"update-one","createdAt":"2026-07-11T00:00:00Z","updatedAt":"2026-07-11T00:00:00Z"}','["posts:post-two","newsTopics:topic-one"]'),
 public.test_restore_news_record('newsUpdatePreviousLinks','link-two',null,5,0,'{"updateId":"update-two","previousUpdateId":"update-one"}','["newsUpdates:update-one","newsUpdates:update-two"]','create'),
 public.test_restore_news_record('sources','source-one','50500000-0000-0000-0000-000000000001',6,0,'{"postId":"post-one","newsUpdateId":"update-one","sourceName":"기관","sourceTitle":"자료","sourceUrl":"https://source.example/item","sourcePublishedAt":null,"checkedAt":null,"checkedPoint":"핵심","sortOrder":0,"createdAt":"2026-07-12T00:00:00Z","updatedAt":"2026-07-12T00:00:00Z"}','["posts:post-one","newsUpdates:update-one"]'),
 public.test_restore_news_record('newsFollowups','followup-one','50600000-0000-0000-0000-000000000001',7,0,'{"topicId":"topic-one","checkText":"후속 확인","status":"pending","dueDate":null,"priority":"high","resolutionNote":null,"resolvedAt":null,"createdAt":"2026-07-12T00:00:00Z","updatedAt":"2026-07-12T00:00:00Z"}','["newsTopics:topic-one"]'),
 public.test_restore_news_record('generatedPrompts','prompt-one','50700000-0000-0000-0000-000000000001',8,0,'{"categoryId":"economy","requestedPostCount":5,"actualPostCount":2,"promptMode":"standard","promptText":"보존할 프롬프트 전문","isPinned":true,"generatedAt":"2026-07-15T03:04:05Z","referenceDate":"2026-07-15","closedLookbackDays":90,"contextSchemaVersion":1,"contextSnapshot":{"schemaVersion":1,"category":{"id":"economy"},"referenceDate":"2026-07-15","recentPosts":[]}}','["category:economy"]')
));
select is((public.finalize_restore_job((select id from news_jobs where name='main'))->>'status'),'ready','1 news job finalized');
select is(public.test_run_restore_news_job((select id from news_jobs where name='main')),10,'2 news and prompt records executed');
select is((select canonical_title from public.news_topics where id='50200000-0000-0000-0000-000000000001'),'경제 주제','3 topic restored');
select is((select changed_at from public.news_status_history where id='50300000-0000-0000-0000-000000000001'),'2026-07-01T01:00:00Z'::timestamptz,'4 status history restored');
select is((select headline from public.news_updates where id='50400000-0000-0000-0000-000000000002'),'후속 업데이트','5 update restored');
select is((select item_order from public.news_updates where id='50400000-0000-0000-0000-000000000002'),2,'6 update item order preserved');
select is((select previous_update_id from public.news_updates where id='50400000-0000-0000-0000-000000000002'),'50400000-0000-0000-0000-000000000001'::uuid,'7 previous link restored');
select is((select source_url from public.sources where id='50500000-0000-0000-0000-000000000001'),'https://source.example/item','8 source restored');
select is((select news_update_id from public.sources where id='50500000-0000-0000-0000-000000000001'),'50400000-0000-0000-0000-000000000001'::uuid,'9 source update link restored');
select is((select status from public.news_followups where id='50600000-0000-0000-0000-000000000001'),'pending','10 followup restored');
select is((select prompt_text from public.generated_prompts where id='50700000-0000-0000-0000-000000000001'),'보존할 프롬프트 전문','11 prompt text preserved');
select is((select context_snapshot from public.generated_prompts where id='50700000-0000-0000-0000-000000000001')->>'referenceDate','2026-07-15','12 prompt snapshot preserved');
select is((select is_pinned from public.generated_prompts where id='50700000-0000-0000-0000-000000000001'),true,'13 prompt pin preserved');
select is((select generated_at from public.generated_prompts where id='50700000-0000-0000-0000-000000000001'),'2026-07-15T03:04:05Z'::timestamptz,'14 prompt timestamp preserved');
select ok(not ((select context_snapshot from public.generated_prompts where id='50700000-0000-0000-0000-000000000001') ? 'ownerId'),'15 prompt snapshot excludes owner ID');

insert into news_jobs values('topic-reuse',public.test_restore_news_job(repeat('b',64),1));
select public.append_restore_job_records((select id from news_jobs where name='topic-reuse'),jsonb_build_array(public.test_restore_news_record('newsTopics','topic-reuse','50200000-0000-0000-0000-000000000001',1,0,'{"categoryId":"economy","topicKey":"economy-topic","canonicalTitle":"경제 주제","topicSummary":"요약","status":"active","closedReason":null,"firstSeenAt":"2026-07-01","lastSeenAt":"2026-07-15","createdAt":"2026-07-01T00:00:00Z","updatedAt":"2026-07-15T00:00:00Z"}','["category:economy"]','reuse_existing'))); select public.finalize_restore_job((select id from news_jobs where name='topic-reuse'));
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='topic-reuse')))->>'status'),'reused','16 topic exact reuse succeeds');

insert into news_jobs values('topic-mismatch',public.test_restore_news_job(repeat('c',64),1));
select public.append_restore_job_records((select id from news_jobs where name='topic-mismatch'),jsonb_build_array(public.test_restore_news_record('newsTopics','topic-mismatch','50200000-0000-0000-0000-000000000001',1,0,'{"categoryId":"economy","topicKey":"economy-topic","canonicalTitle":"변경된 주제","topicSummary":"요약","status":"active","closedReason":null,"firstSeenAt":"2026-07-01","lastSeenAt":"2026-07-15","createdAt":"2026-07-01T00:00:00Z","updatedAt":"2026-07-15T00:00:00Z"}','["category:economy"]','reuse_existing'))); select public.finalize_restore_job((select id from news_jobs where name='topic-mismatch'));
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='topic-mismatch')))->>'errorCode'),'RESTORE_REUSE_MISMATCH','17 topic mismatch blocked');

insert into news_jobs values('self-link',public.test_restore_news_job(repeat('d',64),4));
select public.append_restore_job_records((select id from news_jobs where name='self-link'),jsonb_build_array(public.test_restore_news_record('posts','self-post','50100000-0000-0000-0000-000000000010',1,0,public.test_restore_news_post('self-post','Self Post','2026-07-22'),'["category:economy"]'),public.test_restore_news_record('newsTopics','topic-one','50200000-0000-0000-0000-000000000001',1,1,'{}','[]','reuse_existing'),public.test_restore_news_record('newsUpdates','self-update','50400000-0000-0000-0000-000000000010',2,0,'{"postId":"self-post","topicId":"topic-one","itemOrder":3,"updateType":"follow_up","headline":"self","factSummary":"self fact","importanceSummary":null,"impactSummary":null,"changeSummary":"self","previousUpdateId":null,"createdAt":"2026-07-12T00:00:00Z","updatedAt":"2026-07-12T00:00:00Z"}','["posts:self-post","newsTopics:topic-one"]'),public.test_restore_news_record('newsUpdatePreviousLinks','self-link',null,3,0,'{"updateId":"self-update","previousUpdateId":"self-update"}','["newsUpdates:self-update"]','create'))); select public.finalize_restore_job((select id from news_jobs where name='self-link')); select public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='self-link') and section='posts'));
set local role postgres; update public.restore_job_records set status='reused' where job_id=(select id from news_jobs where name='self-link') and section in ('newsUpdates','newsTopics'); update public.restore_jobs set status='running' where id=(select id from news_jobs where name='self-link'); set local role authenticated; set local "request.jwt.claims"='{"sub":"00000000-0000-0000-0000-000000005001","role":"authenticated"}';
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='self-link') and section='newsUpdatePreviousLinks'))->>'errorCode'),'RESTORE_PREVIOUS_LINK_INVALID','18 previous self link blocked');

insert into news_jobs values('source-mismatch',public.test_restore_news_job(repeat('e',64),3));
select public.append_restore_job_records((select id from news_jobs where name='source-mismatch'),jsonb_build_array(public.test_restore_news_record('posts','post-two','50100000-0000-0000-0000-000000000002',1,0,'{}','[]','reuse_existing'),public.test_restore_news_record('newsUpdates','update-one','50400000-0000-0000-0000-000000000001',1,1,'{}','[]','reuse_existing'),public.test_restore_news_record('sources','source-mismatch','50500000-0000-0000-0000-000000000010',2,0,'{"postId":"post-two","newsUpdateId":"update-one","sourceName":"기관","sourceTitle":"잘못된 연결","sourceUrl":"https://source.example/mismatch","sourcePublishedAt":null,"checkedAt":null,"checkedPoint":"확인","sortOrder":1,"createdAt":"2026-07-12T00:00:00Z","updatedAt":"2026-07-12T00:00:00Z"}','["posts:post-two","newsUpdates:update-one"]'))); select public.finalize_restore_job((select id from news_jobs where name='source-mismatch'));
set local role postgres; update public.restore_job_records set status='reused' where job_id=(select id from news_jobs where name='source-mismatch') and section in ('posts','newsUpdates'); update public.restore_jobs set status='running' where id=(select id from news_jobs where name='source-mismatch'); set local role authenticated; set local "request.jwt.claims"='{"sub":"00000000-0000-0000-0000-000000005001","role":"authenticated"}';
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='source-mismatch') and section='sources'))->>'errorCode'),'RESTORE_SOURCE_LINK_INVALID','19 source cannot link update from another post');

set local role postgres; insert into public.news_topics(id,owner_id,category_id,topic_key,canonical_title,topic_summary,status,closed_reason,first_seen_at,last_seen_at) values('50200000-0000-0000-0000-000000000010','00000000-0000-0000-0000-000000005001','economy','closed-topic','종료 주제',null,'active',null,'2026-07-01','2026-07-15'); update public.news_topics set status='closed',closed_reason='종료' where id='50200000-0000-0000-0000-000000000010'; set local role authenticated; set local "request.jwt.claims"='{"sub":"00000000-0000-0000-0000-000000005001","role":"authenticated"}';
insert into news_jobs values('closed-followup',public.test_restore_news_job(repeat('5',64),2));
select public.append_restore_job_records((select id from news_jobs where name='closed-followup'),jsonb_build_array(public.test_restore_news_record('newsTopics','closed-topic','50200000-0000-0000-0000-000000000010',1,0,'{}','[]','reuse_existing'),public.test_restore_news_record('newsFollowups','closed-pending','50600000-0000-0000-0000-000000000010',2,0,'{"topicId":"closed-topic","checkText":"금지 pending","status":"pending","dueDate":null,"priority":"normal","resolutionNote":null,"resolvedAt":null,"createdAt":"2026-07-12T00:00:00Z","updatedAt":"2026-07-12T00:00:00Z"}','["newsTopics:closed-topic"]'))); select public.finalize_restore_job((select id from news_jobs where name='closed-followup'));
set local role postgres; update public.restore_job_records set status='reused' where job_id=(select id from news_jobs where name='closed-followup') and section='newsTopics'; update public.restore_jobs set status='running' where id=(select id from news_jobs where name='closed-followup'); set local role authenticated; set local "request.jwt.claims"='{"sub":"00000000-0000-0000-0000-000000005001","role":"authenticated"}';
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='closed-followup') and section='newsFollowups'))->>'errorCode'),'RESTORE_INVALID_PAYLOAD','20 closed topic pending followup blocked');
select is((select count(*)::int from public.news_followups where id='50600000-0000-0000-0000-000000000010'),0,'21 blocked followup rolls back');

insert into news_jobs values('bad-prompt',public.test_restore_news_job(repeat('6',64),1));
select public.append_restore_job_records((select id from news_jobs where name='bad-prompt'),jsonb_build_array(public.test_restore_news_record('generatedPrompts','bad-prompt','50700000-0000-0000-0000-000000000010',1,0,'{"categoryId":"economy","requestedPostCount":5,"actualPostCount":0,"promptMode":"standard","promptText":"bad time","isPinned":false,"generatedAt":"not-a-time","referenceDate":"2026-07-15","closedLookbackDays":90,"contextSchemaVersion":1,"contextSnapshot":{"schemaVersion":1,"category":{"id":"economy"},"referenceDate":"2026-07-15","recentPosts":[]}}','["category:economy"]'))); select public.finalize_restore_job((select id from news_jobs where name='bad-prompt'));
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='bad-prompt')))->>'errorCode'),'RESTORE_INVALID_PAYLOAD','22 invalid prompt timestamp blocked');
select is((select status from public.restore_job_records where job_id=(select id from news_jobs where name='bad-prompt')),'failed','23 invalid prompt record remains failed');
select is((select count(*)::int from public.generated_prompts where id='50700000-0000-0000-0000-000000000010'),0,'24 invalid prompt domain write rolled back');
select is((select status from public.restore_jobs where id=(select id from news_jobs where name='bad-prompt')),'paused_with_errors','25 failed last stage pauses with errors');
select is((select attempt_no from public.restore_job_record_attempts where restore_job_record_id=(select id from public.restore_job_records where job_id=(select id from news_jobs where name='bad-prompt'))),1,'26 failed prompt attempt recorded');

insert into news_jobs values('cycle-link',public.test_restore_news_job(repeat('7',64),3));
select public.append_restore_job_records((select id from news_jobs where name='cycle-link'),jsonb_build_array(public.test_restore_news_record('newsUpdates','update-one','50400000-0000-0000-0000-000000000001',1,0,'{}','[]','reuse_existing'),public.test_restore_news_record('newsUpdates','update-two','50400000-0000-0000-0000-000000000002',1,1,'{}','[]','reuse_existing'),public.test_restore_news_record('newsUpdatePreviousLinks','cycle-link',null,2,0,'{"updateId":"update-one","previousUpdateId":"update-two"}','["newsUpdates:update-one","newsUpdates:update-two"]','create'))); select public.finalize_restore_job((select id from news_jobs where name='cycle-link'));
set local role postgres; update public.restore_job_records set status='reused' where job_id=(select id from news_jobs where name='cycle-link') and section='newsUpdates'; update public.restore_jobs set status='running' where id=(select id from news_jobs where name='cycle-link'); set local role authenticated; set local "request.jwt.claims"='{"sub":"00000000-0000-0000-0000-000000005001","role":"authenticated"}';
select is((public.run_restore_job_record((select id from public.restore_job_records where job_id=(select id from news_jobs where name='cycle-link') and section='newsUpdatePreviousLinks'))->>'errorCode'),'RESTORE_PREVIOUS_LINK_INVALID','27 previous cycle link blocked');

select * from finish();
rollback;
